{
  "verses": [
    {
      "n": 41,
      "column": "left",
      "text": "Ta Dehla Atuus / ta\nDehla Seerus/ ta Dehla Adajus.\n"
    },
    {
      "n": 42,
      "column": "left",
      "text": "Ta Dehla Fetana / ta\nDehla Simus/ ta Dehla Si-\nmejus.\n"
    },
    {
      "n": 43,
      "column": "left",
      "text": "Ta Dehla Jaäta / ta\nDehla Gersoxa/ ta Dehla Letwja.\n"
    },
    {
      "n": 44,
      "column": "left",
      "text": "Un winnu Brahti Mera-\nra Behrni stahweja pa kreifo\nRohku/ ar Wahrdü/ Getans Ku-\nsus Dehls/ ta Dehla Abdi / ta\nDehla Malluka.\n"
    },
    {
      "n": 45,
      "column": "left",
      "text": "Ta Dehla Asabijus / ta\nDehla Amazijus/ ta Dehla Il-\nkijus.\n"
    },
    {
      "n": 46,
      "column": "left",
      "text": "Ta Dehla Amzus / ta\nDehla Banus / ta Dehla Sa-\nmerus.\n"
    },
    {
      "n": 47,
      "column": "left",
      "text": "Ta Dehla Maëlus / ta\nDehla Musus/ ta Dehla Mera-\nra/ Lewja Dehla.\n"
    },
    {
      "n": 48,
      "column": "left",
      "text": "Un winnu Brahti tee Le-\nwiti bija eezelti pee wiffadas Kal-\nposchanas ta Deewa Namma\nDsihwokta.\n"
    },
    {
      "n": 49,
      "column": "left",
      "text": "Un Aärongs / un winna\nDehli kwehpinaja us to Dedsa-\nmo- Uppuxu Altari / un us to\nKwehpja-Altari / un bija eezelti\npee wiffa Darba tahs wiffsfweh-\ntakas Weetas/ ka tee Israëlu fa-\nlihdsinatu / pehz wiffu / ka tas\nDeewa Kalps Mohsus bij pa-\nwehlejs.\n"
    },
    {
      "n": 50,
      "column": "left",
      "text": "Un fchee bija Aärona\nBehrni: Eeleasars winna Dehls/\nta Dehls bija Pineas/ ta Dehls\nbija Abisuüs.\n"
    },
    {
      "n": 51,
      "column": "left",
      "text": "Ta Dehls bija Bukus/ ta\n"
    },
    {
      "n": 41,
      "column": "right",
      "text": "Dehls bija Usus/ ta Dehls b\nSerajus.\n"
    },
    {
      "n": 52,
      "column": "right",
      "text": "Ta Dehls bija Merajo-\nta Dehls bija Amarijus /\nDehls bija Afikabs.\n"
    },
    {
      "n": 53,
      "column": "right",
      "text": "Ta Dehls bija Zadaks /\nDehls bija Akimaäz.\n"
    },
    {
      "n": 54,
      "column": "right",
      "text": "Un schahs bija win-\nDsihwoschanas pehz win-\nMeestahin eeksch winnu Roh-\nschahm/(ar Wahrdü/) Aäro-\nBehrneem to Raätiteru Ri-\ndeem/ jo ta nomeslota Teefa b\nwinneem ta nahkusi.\n"
    },
    {
      "n": 55,
      "column": "right",
      "text": "Un tee dewe teem Geb-\nnu eeksch tahs Semmes Juho-\nun winna Preekich-Pilsfaht-\napkahrt winnu.\n"
    },
    {
      "n": 56,
      "column": "right",
      "text": "Bet ta Pilsfahta Tih-\nmus/ un winna Zeemus dewe\nKahlebam Jevuna Dehlan.\n"
    },
    {
      "n": 57,
      "column": "right",
      "text": "Un Aärona Behrne-\ndewe tee Jsglahbschanas - Pi-\nfahtus/ Gebronu un Libnu /\nwinnu Preekich-Pilsfahtus.\n"
    },
    {
      "n": 58,
      "column": "right",
      "text": "Un Jatern/ un Estem-\nun winna Preekich-Pilsfaht-\nUn Jleuu / un winna Preek-\nPilsfahtus/ un Debiru/ un wi-\nna Preekich-Pilsfahtus.\n"
    },
    {
      "n": 59,
      "column": "right",
      "text": "Un Asanu un win-\nPreekich-Pilsfahtus/ un B-\nSeemefu un winna Preek-\nPilsfahtus.\n"
    },
    {
      "n": 60,
      "column": "right",
      "text": "Un no Benjamina Ji-\nGebu un winna Preekich-Pi-\nfahtus/ un Aleinetu un win-\nPreekich-Pilsfahtus / un A-\ntotu un winna Preekich - Pi-\nfahtus/ winfi winna Pilsfa-\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
